        {"variable": "members", "op": "read", "description": "Check owner existence"},
        {"variable": "projects", "op": "read_write", "description": "Add, update, delete projects"},
        {"variable": "tasks", "op": "read_write", "description": "Delete tasks and release members on project deletion"}
      ]
    },
    {
      "name": "HandleTaskCRUD",
      "purpose": "Handles create and delete task commands.",
      "inputs": [
        {"name": "command", "type": "str", "description": "Command: create_task or delete_task", "source": "parent input"},
        {"name": "data", "type": "dict", "description": "Data containing task details", "source": "parent input"}
      ],
      "outputs": [
        {"name": "result", "type": "dict", "description": "JSON with success, message, and data", "consumer": "parent"}
      ],
      "boundary": {
        "in_scope": ["Task creation with project and status validation", "Task deletion with member release"],
        "out_of_scope": ["Task assignment", "Status updates", "Completion"]
