      "behavior": "For create_task: check project exists and its status is 'planning' or 'active', generate new task_id, set title, description, priority, estimated_hours, default status 'todo', no assignee, add to tasks data store, return success. For delete_task: check task exists, if it has an assignee (assignee_id not null) then set that member's availability to 'available', remove task from data store, return success. Errors for invalid project/task, wrong project status.",
      "signature": "def HandleTaskCRUD(command: str, data: dict) -> dict",
      "stop_decompose": true,
      "stop_reason": "Focused on task creation and deletion with necessary validations",
      "global_vars": [
        {"variable": "projects", "op": "read", "description": "Check project existence and status"},
        {"variable": "tasks", "op": "read_write", "description": "Add and delete tasks"},
        {"variable": "members", "op": "read_write", "description": "Release member on task deletion if assigned"}
      ]
    },
    {
      "name": "HandleTaskAssignment",
      "purpose": "Handles assign task, update task status, and complete task commands.",
      "inputs": [
        {"name": "command", "type": "str", "description": "Command: assign_task, update_task_status, or complete_task", "source": "parent input"},
        {"name": "data", "type": "dict", "description": "Data containing task, member, and status details", "source": "parent input"}
      ],
      "outputs": [
        {"name": "result", "type": "dict", "description": "JSON with success, message, and data", "consumer": "parent"}
      ],
      "boundary": {
        "in_scope": ["Task assignment with member validation and skill check", "Status updates with flow enforcement", "Task completion with actual hours and member release"],
        "out_of_scope": ["Task creation/deletion", "Project management", "Query operations"]
      },
      "behavior": "For assign_task: check task exists and is unassigned (assignee_id is null), check member exists and availability is 'available', optionally match skills if provided in data, set task assignee_id to member, set member availability to 'busy', return success. For update_task_status: check task exists, validate transition: from 'todo' to 'in_progress', 'in_progress' to 'review', 'review' to 'done', 'blocked' can be set from any status, if new status is 'done' record actual_hours from data (if not provided default to estimated_hours), update status. For complete_task: check task exists and status is 'review', set status to 'done', record actual_hours from data (if not provided default to estimated_hours), set member availability to 'available' if assignee_id exists, return success. Errors for invalid task/member, invalid transition, missing fields.",
      "signature": "def HandleTaskAssignment(command: str, data: dict) -> dict",
