      "stop_reason": "Covers all task assignment and status changes which are tightly coupled",
      "global_vars": [
        {"variable": "tasks", "op": "read_write", "description": "Update task fields (assignee_id, status, actual_hours)"},
        {"variable": "members", "op": "read_write", "description": "Update member availability (busy/available)"}
      ]
    },
    {
      "name": "HandleListProjectTasks",
      "purpose": "Lists tasks of a project with optional filters.",
      "inputs": [
        {"name": "data", "type": "dict", "description": "Data containing project_id and optional filters (status_filter, priority_filter, assignee_filter)", "source": "parent input"}
      ],
      "outputs": [
        {"name": "result", "type": "dict", "description": "JSON with success, message, and data (list of task details)", "consumer": "parent"}
      ],
      "boundary": {
        "in_scope": ["Retrieving tasks for a valid project", "Filtering by status, priority, assignee", "Returning task details"],
        "out_of_scope": ["Modifying tasks", "Calculating progress", "Member tasks"]
      },
      "behavior": "Check project exists, retrieve all tasks with that project_id from tasks data store, apply filters if provided (status_filter, priority_filter, assignee_filter), return list of task objects (id, title, description, priority, estimated_hours, actual_hours, status, assignee_id, etc.). If project does not exist, return error.",
      "signature": "def HandleListProjectTasks(data: dict) -> dict",
