      "stop_reason": "Simple query operation, no need for further decomposition",
      "global_vars": [
        {"variable": "projects", "op": "read", "description": "Check project existence"},
        {"variable": "tasks", "op": "read", "description": "Fetch tasks by project_id"}
      ]
    },
    {
      "name": "HandleGetMemberTasks",
      "purpose": "Gets all tasks for a given member, both current and historical, and calculates total hours.",
      "inputs": [
        {"name": "data", "type": "dict", "description": "Data containing member_id", "source": "parent input"}
      ],
      "outputs": [
        {"name": "result", "type": "dict", "description": "JSON with success, message, and data containing tasks list and total_hours", "consumer": "parent"}
      ],
      "boundary": {
        "in_scope": ["Retrieving all tasks assigned to a member", "Computing total actual hours"],
        "out_of_scope": ["Project tasks listing", "Progress calculation"]
      },
      "behavior": "Check member exists, query tasks data store for all tasks where assignee_id equals member_id, return list of tasks (including status, hours, etc.) and compute total_hours by summing actual_hours for all tasks (null treated as 0). If member does not exist, return error.",
      "signature": "def HandleGetMemberTasks(data: dict) -> dict",
      "stop_decompose": true,
      "stop_reason": "Straightforward query and aggregation",
      "global_vars": [
        {"variable": "members", "op": "read", "description": "Check member existence"},
        {"variable": "tasks", "op": "read", "description": "Fetch tasks by assignee_id"}
      ]
    },
    {
      "name": "HandleGetProjectProgress",
      "purpose": "Gets project progress statistics including completion rate, hours, and estimated completion time.",
      "inputs": [
        {"name": "data", "type": "dict", "description": "Data containing project_id", "source": "parent input"}
      ],
      "outputs": [
        {"name": "result", "type": "dict", "description": "JSON with success, message, and data containing progress info", "consumer": "parent"}
      ],
      "boundary": {
        "in_scope": ["Computing total tasks, completion rate, status counts", "Comparing estimated vs actual hours", "Estimating completion time"],
        "out_of_scope": ["Listing task details", "Member tasks"]
      },
      "behavior": "Check project exists, retrieve all tasks for that project, compute total_tasks count, count tasks by status (todo, in_progress, review, done, blocked), completion rate = (done count / total tasks) * 100, sum estimated_hours and actual_hours for all tasks, estimate completion time: if any task not done, take average of actual_hours per done task and multiply by remaining tasks and add to current time (or simpler: if total_estimated > 0, remaining estimated hours / average completion rate). Return all stats in data. If project does not exist, return error.",
      "signature": "def HandleGetProjectProgress(data: dict) -> dict",
      "stop_decompose": true,
      "stop_reason": "Aggregation logic is specific and self-contained",
      "global_vars": [
        {"variable": "projects", "op": "read", "description": "Check project existence"},
        {"variable": "tasks", "op": "read", "description": "Fetch tasks by project_id for statistics"}
      ]
    },
    {
      "name": "HandleMemberOperations",
      "purpose": "Handles add member and update member availability commands.",
      "inputs": [
        {"name": "command", "type": "str", "description": "Command: add_member or update_member_availability", "source": "parent input"},
        {"name": "data", "type": "dict", "description": "Data containing member details", "source": "parent input"}
      ],
      "outputs": [
        {"name": "result", "type": "dict", "description": "JSON with success, message, and data", "consumer": "parent"}
      ],
      "boundary": {
        "in_scope": ["Adding a new member with unique ID", "Updating member availability with ongoing task check"],
        "out_of_scope": ["Task assignment", "Project management"]
      },
      "behavior": "For add_member: check member_id is unique, create member entry with name, role, skills, default availability 'available', add to members data store, return success. For update_member_availability: check member exists, if setting availability to 'offline' (or any non-'available'), check if member has any ongoing task (task where status is not 'done' and assignee_id equals member_id), if so return error, otherwise update availability. Return success.",
      "signature": "def HandleMemberOperations(command: str, data: dict) -> dict",
      "stop_decompose": true,
      "stop_reason": "Covers member management operations with necessary validations",
      "global_vars": [
        {"variable": "members", "op": "read_write", "description": "Add new member, update availability"},
        {"variable": "tasks", "op": "read", "description": "Check for ongoing tasks when setting offline"}
      ]
    }
  ],
  "decomposition_rationale": "The parent Project Task Manager routes commands to specialized child functions. Each child handles a cohesive subset of commands: project CRUD (HandleProjectOperations), task creation/deletion (HandleTaskCRUD), task assignment/status changes (HandleTaskAssignment), listing tasks (HandleListProjectTasks), member tasks query (HandleGetMemberTasks), project progress (HandleGetProjectProgress), and member management (HandleMemberOperations). The parent selects the appropriate child based on the command field and passes the data. This separation ensures each child has a clear responsibility, minimal overlap, and operates on the shared global data stores (members, projects, tasks) as needed. No child calls another; the parent orchestrates all calls."
}
